export const VOCAB = _VOCAB.map(w => {
  const lex = LEXICON[w.id]
  return lex ? { ...w, synonyms: lex.synonyms, usage: lex.usage, semantics: lex.semantics } : w
})

export const THEMES = [...new Set(VOCAB.map(w => w.theme))]
